require_once __DIR__ . '/require-member.php';
 $channelsBySlug=[]; foreach((json_decode(file_get_contents(__DIR__ . '/data/channels.json'),true)?:[]) as $channel){$channelsBySlug[(string)($channel['slug']??'')]=$channel;}
